    id: 1,
    title: 'Sample Task',
    status: 'TODO',
    priority: 'MEDIUM',
    assignee: { displayName: 'Alice' },
    tags: [{ name: 'frontend', color: '#3B82F6' }],
  }

  function mountItem(task = baseTask) {
    return mount(TaskListItem, {
      props: { task },
    })
  }

  // AC6: Displays task title
  it('should display the task title', () => {
    const wrapper = mountItem()
    expect(wrapper.text()).toContain('Sample Task')
  })

  // AC6: Displays status badge
  it('should display the status badge', () => {
    const wrapper = mountItem()
    expect(wrapper.text()).toContain('TODO')
  })

  // AC6: Displays priority badge
  it('should display the priority badge', () => {
    const wrapper = mountItem()
    expect(wrapper.text()).toContain('MEDIUM')
  })

  // AC6: Displays assignee displayName
  it('should display the assignee name', () => {
    const wrapper = mountItem()
    expect(wrapper.text()).toContain('Alice')
  })

  // AC6: Shows "Not assigned" when no assignee
  it('should show "Not assigned" when assignee is null', () => {
    const task = { ...baseTask, assignee: null }
    const wrapper = mountItem(task)
    const text = wrapper.text().toLowerCase()
    expect(text).toMatch(/not\s*assigned|未指派|unassigned/)
  })

  // AC6: Displays tags
  it('should display tag names', () => {
    const wrapper = mountItem()
    expect(wrapper.text()).toContain('frontend')
  })

  // AC6: Handles empty tags
  it('should handle empty tags gracefully', () => {
    const task = { ...baseTask, tags: [] }
    const wrapper = mountItem(task)
    expect(wrapper.text()).toContain('Sample Task')
  })

  // AC7: Status badge colors - TODO = #6B7280 (gray)
