    const task = { ...baseTask, status: 'IN_PROGRESS' }
    const wrapper = mountItem(task)
    const html = wrapper.html()
    expect(html).toContain('#3B82F6')
  })

  // AC7: Status badge colors - DONE = #10B981 (green)
  it('should use green color (#10B981) for DONE status', () => {
    const task = { ...baseTask, status: 'DONE' }
    const wrapper = mountItem(task)
    const html = wrapper.html()
    expect(html).toContain('#10B981')
  })

  // AC7: Status badge colors - CLOSED = #EF4444 (red)
  it('should use red color (#EF4444) for CLOSED status', () => {
    const task = { ...baseTask, status: 'CLOSED' }
    const wrapper = mountItem(task)
    const html = wrapper.html()
    expect(html).toContain('#EF4444')
  })

  // AC8: Priority badge colors - HIGH = #EF4444 (red)
  it('should use red color (#EF4444) for HIGH priority', () => {
    const task = { ...baseTask, priority: 'HIGH' }
    const wrapper = mountItem(task)
    const html = wrapper.html()
    expect(html).toContain('#EF4444')
  })

  // AC8: Priority badge colors - MEDIUM = #F59E0B (orange)
  it('should use orange color (#F59E0B) for MEDIUM priority', () => {
    const task = { ...baseTask, priority: 'MEDIUM' }
    const wrapper = mountItem(task)
    const html = wrapper.html()
    expect(html).toContain('#F59E0B')
  })

  // AC8: Priority badge colors - LOW = #10B981 (green)
  it('should use green color (#10B981) for LOW priority', () => {
    const task = { ...baseTask, priority: 'LOW' }
    const wrapper = mountItem(task)
    const html = wrapper.html()
    expect(html).toContain('#10B981')
  })

  // AC9: Emits click event
