import { describe, it, expect, vi, beforeEach } from 'vitest'
import { mount, flushPromises } from '@vue/test-utils'
import { createPinia, setActivePinia } from 'pinia'
import TaskCreateForm from '@/components/TaskCreateForm.vue'

vi.mock('@/api/tasks', () => ({
  fetchTasks: vi.fn().mockResolvedValue({
    content: [],
    page: 0,
    size: 20,
    totalElements: 0,
    totalPages: 0,
  }),
  createTask: vi.fn().mockResolvedValue({ id: 1, title: 'New', status: 'TODO', priority: 'MEDIUM' }),
}))

describe('TaskCreateForm', () => {
  beforeEach(() => {
    setActivePinia(createPinia())
  })

  function mountForm(visible = true) {
    return mount(TaskCreateForm, {
      props: { visible },
      global: {
        plugins: [createPinia()],
      },
    })
  }

  // AC10: Form is visible when visible prop is true
  it('should render form when visible is true', () => {
    const wrapper = mountForm(true)
    expect(wrapper.find('form').exists() || wrapper.find('input').exists()).toBe(true)
  })

  // Form is hidden when visible is false
  it('should not render form content when visible is false', () => {
    const wrapper = mountForm(false)
    // Either the entire component is empty or the form is hidden
    const form = wrapper.find('form')
    const input = wrapper.find('input')
    expect(!form.exists() || !input.exists() || wrapper.html() === '' || wrapper.html() === '<!---->').toBe(true)
  })

  // AC11: Has title input field (required)
  it('should have a title input field', () => {
    const wrapper = mountForm(true)
    const titleInput = wrapper.find('input[name="title"], input#title, input[placeholder*="title" i]')
    // Fallback: look for any text input
    const anyInput = wrapper.find('input[type="text"], input:not([type])')
    expect(titleInput.exists() || anyInput.exists()).toBe(true)
  })

  // AC11: Has description field (optional)
  it('should have a description field', () => {
    const wrapper = mountForm(true)
    const desc = wrapper.find('textarea, input[name="description"]')
    expect(desc.exists()).toBe(true)
  })

  // AC11: Has priority dropdown with default MEDIUM
  it('should have a priority dropdown defaulting to MEDIUM', () => {
    const wrapper = mountForm(true)
    const select = wrapper.find('select')
    expect(select.exists()).toBe(true)
    const options = select.findAll('option')
    const values = options.map((o) => o.element.value)
    expect(values).toContain('HIGH')
    expect(values).toContain('MEDIUM')
    expect(values).toContain('LOW')
    // Default should be MEDIUM
    expect((select.element as HTMLSelectElement).value).toBe('MEDIUM')
  })

  // AC11: Submit calls createTask with form data
  it('should call store.createTask on submit', async () => {
    const wrapper = mountForm(true)
    const { useTaskStore } = await import('@/stores/taskStore')
    const store = useTaskStore()
    const spy = vi.spyOn(store, 'createTask')

    // Fill in the title
    const titleInput = wrapper.find('input[type="text"], input:not([type])')
    await titleInput.setValue('New Task Title')

    // Submit the form
    const form = wrapper.find('form')
    if (form.exists()) {
      await form.trigger('submit')
    } else {
      // Try finding a submit button
      const submitBtn = wrapper.findAll('button').find(
        (b) => b.attributes('type') === 'submit' || b.text().toLowerCase().includes('submit') || b.text().includes('建立') || b.text().toLowerCase().includes('create')
      )
      await submitBtn!.trigger('click')
    }
    await flushPromises()

    expect(spy).toHaveBeenCalledWith(
      expect.objectContaining({ title: 'New Task Title' })
    )
  })

  // AC12: Emits 'created' event on successful creation
  it('should emit "created" after successful task creation', async () => {
    const wrapper = mountForm(true)

    const titleInput = wrapper.find('input[type="text"], input:not([type])')
    await titleInput.setValue('New Task')

    const form = wrapper.find('form')
    if (form.exists()) {
      await form.trigger('submit')
    } else {
      const submitBtn = wrapper.findAll('button').find(
        (b) => b.attributes('type') === 'submit' || b.text().toLowerCase().includes('create') || b.text().includes('建立')
      )
      await submitBtn!.trigger('click')
    }
    await flushPromises()

    expect(wrapper.emitted('created')).toBeTruthy()
  })

  // Emits 'cancel' when cancel button clicked
  it('should emit "cancel" when cancel is clicked', async () => {
    const wrapper = mountForm(true)

    const cancelBtn = wrapper.findAll('button').find(
      (b) => b.text().toLowerCase().includes('cancel') || b.text().includes('取消')
    )
    expect(cancelBtn).toBeTruthy()
    await cancelBtn!.trigger('click')

    expect(wrapper.emitted('cancel')).toBeTruthy()
  })

  // Title validation: required field (1-200 chars)
  it('should not submit when title is empty', async () => {
    const wrapper = mountForm(true)
    const { useTaskStore } = await import('@/stores/taskStore')
    const store = useTaskStore()
    const spy = vi.spyOn(store, 'createTask')

    // Leave title empty and try to submit
    const form = wrapper.find('form')
    if (form.exists()) {
      await form.trigger('submit')
    } else {
      const submitBtn = wrapper.findAll('button').find(
        (b) => b.attributes('type') === 'submit' || b.text().toLowerCase().includes('create') || b.text().includes('建立')
      )
      if (submitBtn) await submitBtn.trigger('click')
    }
    await flushPromises()

    expect(spy).not.toHaveBeenCalled()
  })
})

import { describe, it, expect } from 'vitest'
import { mount } from '@vue/test-utils'
import Pagination from '@/components/Pagination.vue'

describe('Pagination', () => {
  function mountPagination(currentPage = 0, totalPages = 5) {
    return mount(Pagination, {
      props: { currentPage, totalPages },
    })
  }

  // AC13: Displays page info (current page / total pages)
  it('should display page information', () => {
    const wrapper = mountPagination(0, 5)
    const text = wrapper.text()
    // Should show something like "1 / 5" or "Page 1 of 5"
    expect(text).toMatch(/1/)
    expect(text).toMatch(/5/)
  })

  // AC13: Has Prev and Next buttons
  it('should have Prev and Next buttons', () => {
    const wrapper = mountPagination(1, 5)
    const buttons = wrapper.findAll('button')
    expect(buttons.length).toBeGreaterThanOrEqual(2)
    const texts = buttons.map((b) => b.text().toLowerCase())
    const hasPrev = texts.some((t) => t.includes('prev') || t.includes('上一') || t.includes('<') || t.includes('previous'))
    const hasNext = texts.some((t) => t.includes('next') || t.includes('下一') || t.includes('>'))
    expect(hasPrev).toBe(true)
    expect(hasNext).toBe(true)
  })

  // AC15: Prev button disabled on first page (page 0)
  it('should disable Prev button on first page', () => {
    const wrapper = mountPagination(0, 5)
    const buttons = wrapper.findAll('button')
    const prevBtn = buttons.find((b) => {
      const t = b.text().toLowerCase()
      return t.includes('prev') || t.includes('上一') || t.includes('<') || t.includes('previous')
    })
    expect(prevBtn).toBeTruthy()
    expect(prevBtn!.attributes('disabled')).toBeDefined()
  })

  // AC15: Next button disabled on last page
  it('should disable Next button on last page', () => {
    const wrapper = mountPagination(4, 5) // page 4 = last (0-indexed, totalPages=5)
    const buttons = wrapper.findAll('button')
    const nextBtn = buttons.find((b) => {
      const t = b.text().toLowerCase()
      return t.includes('next') || t.includes('下一') || t.includes('>')
    })
    expect(nextBtn).toBeTruthy()
    expect(nextBtn!.attributes('disabled')).toBeDefined()
  })

  // Prev button enabled on non-first page
  it('should enable Prev button when not on first page', () => {
    const wrapper = mountPagination(2, 5)
    const buttons = wrapper.findAll('button')
    const prevBtn = buttons.find((b) => {
      const t = b.text().toLowerCase()
      return t.includes('prev') || t.includes('上一') || t.includes('<') || t.includes('previous')
    })
    expect(prevBtn).toBeTruthy()
    expect(prevBtn!.attributes('disabled')).toBeUndefined()
  })

  // Next button enabled on non-last page
  it('should enable Next button when not on last page', () => {
    const wrapper = mountPagination(0, 5)
    const buttons = wrapper.findAll('button')
    const nextBtn = buttons.find((b) => {
      const t = b.text().toLowerCase()
      return t.includes('next') || t.includes('下一') || t.includes('>')
    })
    expect(nextBtn).toBeTruthy()
    expect(nextBtn!.attributes('disabled')).toBeUndefined()
  })

  // AC14: Clicking Next emits page-change with next page number
  it('should emit page-change with next page on Next click', async () => {
    const wrapper = mountPagination(1, 5)
    const buttons = wrapper.findAll('button')
    const nextBtn = buttons.find((b) => {
      const t = b.text().toLowerCase()
      return t.includes('next') || t.includes('下一') || t.includes('>')
    })
    await nextBtn!.trigger('click')
    expect(wrapper.emitted('page-change')).toBeTruthy()
    expect(wrapper.emitted('page-change')![0]).toEqual([2])
  })

  // AC14: Clicking Prev emits page-change with previous page number
  it('should emit page-change with previous page on Prev click', async () => {
    const wrapper = mountPagination(2, 5)
    const buttons = wrapper.findAll('button')
    const prevBtn = buttons.find((b) => {
      const t = b.text().toLowerCase()
      return t.includes('prev') || t.includes('上一') || t.includes('<') || t.includes('previous')
    })
    await prevBtn!.trigger('click')
    expect(wrapper.emitted('page-change')).toBeTruthy()
    expect(wrapper.emitted('page-change')![0]).toEqual([1])
  })

  // Boundary: single page (totalPages=1)
  it('should disable both buttons when there is only one page', () => {
    const wrapper = mountPagination(0, 1)
    const buttons = wrapper.findAll('button')
    buttons.forEach((b) => {
      expect(b.attributes('disabled')).toBeDefined()
    })
  })

  // Boundary: totalPages=0 (no data)
  it('should handle totalPages=0 gracefully', () => {
    const wrapper = mountPagination(0, 0)
    expect(wrapper.exists()).toBe(true)
  })
})

